import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limiting the buffer size to avoid buffer overflow
        int bufferSize = Math.min(input.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copy input into buffer with proper length checking
        for (int i = 0; i < bufferSize; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

